import type { Page } from '@playwright/test';
import { expect } from '@playwright/test';

export class PublicActionPage {
  constructor(public readonly page: Page) {}

  async testLoadedState() {
    await Promise.all([
      expect(this.page.locator('.chakra-spinner')).toHaveCount(1),
      this.page.waitForResponse((res) =>
        res.url().includes('/public/v3/action_pages/playwright_test_page?account_slug=washington')
      ),
    ]);
  }

  // Mock the api calls
  async mockRoutes() {
    await this.page.route('**/user/v3/me**', async (route) => {
      const json = { error: '"You need to sign in or sign up before continuing."' };

      await route.fulfill({ json, status: 401 });
    });
    await this.page.route('**/user/v3/donor_profile**', async (route) => {
      const json = { error: '"You need to sign in or sign up before continuing."' };

      await route.fulfill({ json, status: 401 });
    });
    await this.page.route('**/public/v3/logins/focus**', async (route) => {
      await route.fulfill({ json: { url: '' } });
    });
  }

  async mockActionPageGet({ body, path }: { body: object; path: string }) {
    await this.page.route(path, async (route) => {
      const json = body;

      await route.fulfill({ json, status: 200 });
    });
  }

  async mockEventPageSubmissionResponse({ json }: { json: object }) {
    await this.page.route('**/public/v3/submissions/event', async (route, request) => {
      if (request.method() === 'POST') {
        // Mock a 3 second request time
        setTimeout(async () => {
          await route.fulfill({
            json,
            status: 200,
          });
        }, 3000);
      } else {
        await route.continue();
      }
    });
  }
}
