import { Flex, Link, VStack } from '@chakra-ui/react';
import { Trans, useTranslation } from 'react-i18next';
import { useCreateAccount, useGetAccount, useUpdateAccount } from '@state/accounts';
import { Button } from '@ui/components/Button';
import { ArchBackgroundLayout } from '@ui/components/Layout/ArchBackgroundLayout';
import { Loading } from '@ui/components/Loading';
import { Panel } from '@ui/components/Panel';
import { Form } from '@ui/components/formControls/Form';
import { Heading, Paragraph } from '@ui/components/typography';
import { useSteps } from '../useSteps';
import { Category } from './Category';
import DisplayName from './DisplayName';
import { useSchema } from './useSchema';

export function NameAndType() {
  const { t } = useTranslation('organizationApplication', { keyPrefix: 'nameAndType' });
  const schema = useSchema({ displayNameRequired: t('displayName.required') });

  const { createAccount, createAccountIsLoading } = useCreateAccount();
  const { currentAccount, isLoading: getAccountIsLoading } = useGetAccount();
  const { isLoading: updateAccountIsLoading, updateAccount } = useUpdateAccount();

  const { navigateNextStep } = useSteps();

  if (getAccountIsLoading) {
    return <Loading />;
  }

  const initialValues = {
    category: currentAccount?.category || 'political',
    displayName: currentAccount?.displayName || '',
  };

  const createAccountWithRedirect = (values: typeof initialValues) => {
    createAccount({ ...values, name: values.displayName }, { onSuccess: navigateNextStep });
  };

  const updateAccountWithRedirect = (values: typeof initialValues) => {
    updateAccount({ updates: values }, { onSuccess: navigateNextStep });
  };

  const onSubmit = currentAccount ? updateAccountWithRedirect : createAccountWithRedirect;

  return (
    <ArchBackgroundLayout variant="lightGreenLaptop">
      <Flex direction="column" gap={4}>
        <hgroup>
          <Heading as="h1">{t('heading')}</Heading>
          <Paragraph as="h2">{t('subheading')}</Paragraph>
        </hgroup>
        <Panel maxW={{ base: 'none', lg: '448px' }} p={6} variant="primary">
          <Form initialValues={initialValues} onSubmit={onSubmit} schema={schema}>
            {({ watch }) => (
              <VStack alignItems="stretch" spacing={8}>
                <DisplayName />
                <Category category={watch('category')} />
                <Button
                  disabled={createAccountIsLoading || updateAccountIsLoading}
                  isFullWidth
                  size="lg"
                  type="submit"
                  variant="primary"
                >
                  {t(`submit.${currentAccount ? 'update' : 'create'}`)}
                </Button>
              </VStack>
            )}
          </Form>
        </Panel>
        <Paragraph>
          {/* eslint-disable-next-line @typescript-eslint/ban-ts-comment */}
          {/* @ts-ignore */}
          <Trans
            components={[<Link href="/dashboard" key="footer-link" />]}
            i18nKey="footer"
            t={t}
          />
        </Paragraph>
      </Flex>
    </ArchBackgroundLayout>
  );
}
