import { useEffect } from 'react';
import { useFormContext } from 'react-hook-form';
import { AccountCategory } from '@domain/accountCategory';
import { useGetAccount } from '@state/accounts';

const CATEGORY_TO_SUBCATEGORIES = {
  'church-ministry': ['church', 'ministry', 'parachurch'],
  education: ['preschool', 'k12', 'higher-education'],
  nonprofit: ['501c3', '501c4', '501c5', '501c6', '501c7', '501c8', '501c10', '501c19'],
  political: ['federal', 'state', 'county', 'local', 'tribal', 'pac', 'party'],
  vendor: null,
} as const;

export const useSubcategories = (category: string) => {
  const { setValue, unregister } = useFormContext();
  const { currentAccount } = useGetAccount();
  const subcategories = CATEGORY_TO_SUBCATEGORIES[category as AccountCategory];

  const hasSubcategories = !!subcategories;
  const hasReligious = ['education'].includes(category);

  useEffect(() => {
    setValue(
      'subCategory',
      (category === currentAccount?.category && currentAccount?.subCategory) || subcategories?.[0]
    );

    if (hasReligious) {
      setValue('religious', currentAccount?.religious || false);
    } else {
      unregister('religious');
    }
  }, [
    category,
    currentAccount?.category,
    currentAccount?.religious,
    currentAccount?.subCategory,
    hasReligious,
    setValue,
    subcategories,
    unregister,
  ]);

  return { category, hasReligious, hasSubcategories, subcategories };
};
