import axios, { AxiosError, AxiosRequestConfig, AxiosResponse } from 'axios';
import { v4 } from 'uuid';
import { IErrorResponse } from '@domain/error';
import { getApiHostname } from '@utils/getApiHostname';
import { isDevelopment } from '@utils/isDevelopment';

const LOGIN_PATH = '/login';
const LOCAL_LOGIN = `http://anedot.me:3000${LOGIN_PATH}`;

export enum ApiClientErrorTypes {
  Axios = 'AXIOS_ERROR',
  Network = 'NETWORK_ERROR',
  Unknown = 'UNKNOWN_ERROR',
}

export type ApiClientError =
  | {
      message: string;
      type: ApiClientErrorTypes.Network | ApiClientErrorTypes.Unknown;
    }
  | ({
      response: AxiosError<IErrorResponse, unknown>['response'];
      type: ApiClientErrorTypes.Axios;
    } & IErrorResponse);

const deserializeError = (error: unknown): ApiClientError => {
  // When we get a network error it's this specific message by axios
  // See more: https://github.com/axios/axios/issues/383
  if ((error as { message: string })?.message === 'Network Error') {
    return { message: 'A network error occurred.', type: ApiClientErrorTypes.Network };
  }

  if (axios.isAxiosError(error)) {
    const axiosError = error as unknown as AxiosError<IErrorResponse>;
    const data = axiosError?.response?.data;
    return { ...data, response: error.response, type: ApiClientErrorTypes.Axios };
  }

  return { message: 'Something went wrong.', type: ApiClientErrorTypes.Unknown };
};

export type PostConfig = Pick<
  AxiosRequestConfig,
  'headers' | 'baseURL' | 'signal' | 'onUploadProgress'
> & {
  interval?: number;
  retries?: number;
};
type PutConfig = Pick<AxiosRequestConfig, 'baseURL' | 'onUploadProgress'>;

export type ApiNamespace = 'org' | 'user' | 'admin' | 'public';

type ApiClientParams = {
  baseURL?: string;
  namespace?: ApiNamespace;
  performRedirect?: boolean;
};

export class ApiClient {
  client;

  constructor({ baseURL, namespace = 'org', performRedirect = true }: ApiClientParams = {}) {
    this.client = axios.create({
      baseURL: baseURL || `${getApiHostname()}/${namespace}/v3`,
      headers: {
        Accept: 'application/json',
        'Content-Type': 'application/json',
        'X-APP': 'anedot:3',
        'X-Requested-With': 'XMLHttpRequest',
      },
      withCredentials: true,
      xsrfCookieName: '_anedot_session',
      xsrfHeaderName: 'X-CSRF-TOKEN',
    });

    // 401 Interceptor
    this.client.interceptors.response.use(undefined, (error) => {
      if (error.response?.status === 401 && performRedirect) {
        const path = isDevelopment() ? LOCAL_LOGIN : LOGIN_PATH;
        const redirectParams = new URLSearchParams({ return_to: window.location.href });
        window.location.assign(`${path}?${redirectParams.toString()}`);
      }
      throw error;
    });
  }

  async get<T>(url: string, config?: AxiosRequestConfig): Promise<T> {
    try {
      const response = await this.client.get<T>(url, config);
      return response.data;
    } catch (error) {
      // eslint-disable-next-line @typescript-eslint/no-throw-literal
      throw deserializeError(error);
    }
  }

  async retryRequest<T>({
    interval,
    request,
    retries,
  }: {
    interval: number;
    request: () => Promise<AxiosResponse<T>>;
    retries: number;
  }): Promise<AxiosResponse<T>> {
    try {
      const result = await request();

      return result;
    } catch (error) {
      const deserializedError = deserializeError(error);
      if (retries > 0 && deserializedError.type === ApiClientErrorTypes.Network) {
        await new Promise((resolve) => setTimeout(resolve, interval));

        return this.retryRequest({
          interval: interval * 2,
          request,
          retries: retries - 1,
        });
      } else {
        // eslint-disable-next-line @typescript-eslint/no-throw-literal
        throw deserializedError;
      }
    }
  }

  async postRaw<TBody, TResults>(
    url: string,
    body?: TBody,
    config?: PostConfig
  ): Promise<AxiosResponse<TResults>> {
    const { interval = 1000, retries = 2 } = config || {};
    // Create an Idempotency Key that will stay the same through each retry
    const idempotencyKey = v4();

    const response = await this.retryRequest<TResults>({
      interval,
      request: () =>
        this.client.post<TResults>(url, body, {
          ...config,
          headers: {
            ...config?.headers,
            'Idempotency-Key': idempotencyKey,
          },
        }),
      retries,
    });
    return response;
  }

  async post<TBody, TResults>(url: string, body?: TBody, config?: PostConfig): Promise<TResults> {
    const { data } = await this.postRaw<TBody, TResults>(url, body, config);
    return data;
  }

  async put<TBody, TResults>(url: string, body?: TBody, config?: PutConfig): Promise<TResults> {
    try {
      const response = await this.client.put<TResults>(url, body, config);
      return response.data;
    } catch (error) {
      // eslint-disable-next-line @typescript-eslint/no-throw-literal
      throw deserializeError(error);
    }
  }

  async patch<TBody, TResults>(url: string, body?: TBody): Promise<TResults> {
    try {
      const response = await this.client.patch<TResults>(url, body);
      return response.data;
    } catch (error) {
      // eslint-disable-next-line @typescript-eslint/no-throw-literal
      throw deserializeError(error);
    }
  }

  async delete<T>(url: string): Promise<T> {
    try {
      const response = await this.client.delete<T>(url);
      return response.data;
    } catch (error) {
      if (axios.isAxiosError(error)) {
        const axiosError = error as unknown as AxiosError<IErrorResponse>;
        const data = axiosError?.response?.data;
        if (data) {
          // eslint-disable-next-line @typescript-eslint/no-throw-literal
          throw data;
        } else {
          // eslint-disable-next-line @typescript-eslint/no-throw-literal
          throw { message: 'Something went wrong.' };
        }
      } else {
        throw error;
      }
    }
  }
}
