import { useTranslation } from 'react-i18next';
import { useMutation } from 'react-query';
import { Account, AccountImage } from '@domain/account';
import { IErrorResponse } from '@domain/error';
import { ApiClient } from '@service/anedot/client';
import { useUploadImage } from '@state/account_images';
