import { resourceKeys, useCacheHelper } from '@state/cacheHelper';
import { useToast } from '@ui/components/Toast';

export type AccountUpdates = Partial<
  Pick<
    Account,
    | 'description'
    | 'disclaimer'
    | 'displayName'
    | 'district'
    | 'electionDate'
    | 'email'
    | 'entityType'
    | 'establishedDate'
    | 'facebook'
    | 'imageId'
    | 'favIconId'
    | 'instagram'
    | 'name'
    | 'phone'
    | 'politicalParty'
    | 'publicAddressId'
    | 'purpose'
    | 'religious'
    | 'slug'
    | 'softDescriptor'
    | 'subCategory'
    | 'subCategoryType'
    | 'subPurpose'
    | 'taxid'
    | 'timeZone'
    | 'twitter'
    | 'url'
  > & {
    signature: string | null;
    signature501c4: string | null;
    title501c4: string | null;
  }
>;

interface IProps {
  file?: AccountImage;
  updates?: AccountUpdates;
}

type Params = {
  shouldShowErrorToast?: boolean;
  shouldShowSuccessToast?: boolean;
  shouldShowToast?: boolean;
};

export const useUpdateAccount = (
  { shouldShowErrorToast, shouldShowSuccessToast, shouldShowToast = true }: Params = {
    shouldShowToast: true,
  }
) => {
  const { showToast } = useToast();
  const { currentAccount } = useGetAccount();
  const { uploadImage } = useUploadImage();
  const accountId = currentAccount?.id;
  const { t } = useTranslation('accounts');
  const { refreshCache } = useCacheHelper(resourceKeys.accounts);

  const {
    error: updateError,
    isLoading: updateLoading,
    mutate: updateAccount,
    mutateAsync: updateAccountAsync,
  } = useMutation<Account, IErrorResponse, IProps, string>(
    async ({ file, updates }: IProps) => {
      let body;
      if (file) {
        const image = await uploadImage(file);
        body = { ...updates, imageId: image?.id };
      } else {
        body = { ...updates };
      }
      return new ApiClient().put<AccountUpdates, Account>(`/accounts/${accountId}`, body);
    },
    {
      onError: () => {
        if (shouldShowToast || shouldShowErrorToast) {
          showToast({
            message: t('state.update.onError'),
            variant: 'error',
          });
        }
      },
      onSuccess: () => {
        if (shouldShowToast || shouldShowSuccessToast) {
          showToast({
            message: t('state.update.onSuccess'),
            variant: 'success',
          });
        }

        return refreshCache(accountId!);
      },
    }
  );

  const { isLoading: pauseLoading, mutate: pauseAccount } = useMutation(
    (body: { reason: string }) => new ApiClient().patch(`/accounts/${accountId}/pause`, body),
    {
      onError: () => {
        showToast({
          message: t('state.pause.onError'),
          variant: 'error',
        });
      },
      onSuccess: () => {
        showToast({
          message: t('state.pause.onSuccess'),
          variant: 'success',
        });

        return refreshCache(accountId!);
      },
    }
  );

  const { isLoading: unpauseLoading, mutate: unpauseAccount } = useMutation(
    () => new ApiClient().patch(`/accounts/${accountId}/unpause`),
    {
      onError: () => {
        showToast({
          message: t('state.unpause.onError'),
          variant: 'error',
        });
      },
      onSuccess: async () => {
        showToast({
          message: t('state.unpause.onSuccess'),
          variant: 'success',
        });

        return refreshCache(accountId!);
      },
    }
  );

  const { isLoading: submitLoading, mutate: submitAccount } = useMutation<
    Partial<Account>,
    IErrorResponse,
    IProps,
    string
  >(() => new ApiClient().patch(`/accounts/${accountId}/submit`), {
    onError: () => {
      showToast({
        message: t('state.submit.onError'),
        variant: 'error',
      });
    },
    onSuccess: async () => {
      showToast({
        message: t('state.submit.onSuccess'),
        variant: 'success',
      });

      return refreshCache(accountId!);
    },
  });

  return {
    error: updateError,
    isLoading: updateLoading || pauseLoading || unpauseLoading || submitLoading,
    pauseAccount,
    submitAccount,
    unpauseAccount,
    updateAccount,
    updateAccountAsync,
  };
};
