import { rest } from 'msw';
import { Account } from '@domain/account';
import { db } from '../db';
import { PaginatedResponse } from '../interfaces';
import { getPaginationQueryParams, getResponseMeta } from '../utils';

const handlers = [
  rest.get<PaginatedResponse<Account>>('/user/v3/accounts', (req, res, ctx) => {
    const { skip, take } = getPaginationQueryParams(req);
    const totalCount = db.account.count();
    const paginatedResponse = {
      data: db.account.findMany({ skip, take }),
      meta: getResponseMeta(take, skip, totalCount),
    };
    return res(ctx.status(200), ctx.json(paginatedResponse));
  }),
];

export default handlers;
