import { useMemo } from 'react';
import { Declined } from '@pages/OrganizationApplication/AccountStatus/Declined';
import { generatePath, matchPath, Navigate, Outlet, useLocation } from 'react-router-dom';
import { useGetAccount } from '@state/accounts';
import { useFeatureFlag } from '@state/featureFlags';
import { useGetMe } from '@state/user/me';
import { PageLayout } from '@ui/components/Layout/PageLayout';
import { getBasePaths } from '@ui/utils/getBasePaths';
import { PageTitle } from '../PageTitle';

const { basePath } = getBasePaths();

export const AccountSwitch = () => {
  const { currentAccount, isFetched, isLoading } = useGetAccount();
  const { user } = useGetMe({ accountId: currentAccount?.id });
  const { pathname } = useLocation();
  const bypassApplicationStatus = useFeatureFlag('access.bypassApplicationStatus');

  const children = useMemo(() => {
    const isStaff = user?.staffRole;

    // Force user to accept ownership of account if pending
    if ((user?.potentialOwners || []).length > 0 && !pathname.includes('ownership')) {
      return (
        <Navigate
          replace
          to={generatePath(`/accounts/:accountId/ownership`, {
            accountId: user!.potentialOwners![0].accountId,
          })}
        />
      );
    }

    if (!isLoading && !currentAccount) {
      // Account doesn't exist
      const path = '/accounts';

      if (!pathname.startsWith(path)) {
        return <Navigate replace to={path} />;
      }
    }

    // Allow staff to bypass
    if (isStaff) {
      return <Outlet />;
    }

    if (currentAccount?.status === 'declined') {
      return <Declined />;
    }

    // Allow access to setup / onboarding regardless of account status other than declined
    if (matchPath('/accounts/:accountId/setup/*', pathname)) {
      return <Outlet />;
    }

    if (currentAccount?.status === 'draft') {
      // Redirect draft accounts to application unless they are already there
      const path = generatePath('/accounts/:accountId/application', {
        accountId: currentAccount?.id,
      });

      if (!pathname.startsWith(path)) {
        return <Navigate replace to={path} />;
      }
    }

    if (!bypassApplicationStatus && currentAccount?.status === 'pending') {
      // Redirect to application status for pending accounts if not staff unless on application
      const parentPath = generatePath('/accounts/:accountId/application', {
        accountId: currentAccount?.id,
      });
      const targetPath = generatePath('/accounts/:accountId/application/status', {
        accountId: currentAccount?.id,
      });

      if (!pathname.startsWith(parentPath)) {
        return <Navigate replace to={targetPath} />;
      }
    }

    return <Outlet />;
  }, [bypassApplicationStatus, currentAccount, isLoading, pathname, user]);

  if (!currentAccount && isFetched) {
    window.location.href = `${basePath}/404`;
    return null;
  }

  if (matchPath(`/accounts/:accountId/builder/*`, pathname)) {
    // Don't render the normal page layout for the builder
    return (
      <>
        <PageTitle />
        {children}
      </>
    );
  }

  return (
    <>
      <PageTitle />
      <PageLayout>{children}</PageLayout>
    </>
  );
};

export default AccountSwitch;
