import { useQuery } from 'react-query';
import { IUserMeResponse } from '@domain/user';
import { ApiClient } from '@service/anedot/client';
import { generateQueryKey, resourceKeys } from '@state/cacheHelper';
import { makeSearchParams } from '@utils';
import { TaskQueue } from '@utils/taskQueue';

type Params = {
  accountId?: string;
  enabled?: boolean;
  performRedirect?: boolean;
  queue?: TaskQueue<IUserMeResponse>;
};

export const useGetMe = ({ accountId, enabled, performRedirect = true, queue }: Params) => {
  const queryParams = makeSearchParams({ account_id: accountId });

  const { data, isLoading } = useQuery(
    generateQueryKey({ accountId, resourceKey: resourceKeys.user.user }),
    async ({ signal }) => {
      const task = () =>
        new ApiClient({ namespace: 'user', performRedirect }).get<IUserMeResponse>(
          `/me?${queryParams.toString()}`,
          { signal }
        );

      return queue ? queue.enqueue(task) : task();
    },
    {
      enabled,
      staleTime: 60000, // 1 minute
    }
  );

  return {
    isLoadingUser: isLoading,
    user: data,
  };
};
