import { ComponentProps } from 'react';
import { Box, Radio, useMultiStyleConfig, VisuallyHidden } from '@chakra-ui/react';
import { Label, Meta } from '@ui/components/typography';
import { useRadioGroupContext } from '../RadioGroup/hooks/useRadioGroupContext';

type BoxRadioControlProps = WithChildren & {
  description?: string;
  isDisabled?: boolean;
  label: string;
  value: string;
  variant?: string;
};

export const BoxRadioControl = ({
  children,
  description,
  isDisabled,
  label,
  value,
  variant,
}: BoxRadioControlProps) => {
  const { getRadioProps, isDisabled: groupDisabled } = useRadioGroupContext();
  const radioProps = getRadioProps({ value });
  const { isChecked, onChange } = radioProps;
  const styles = useMultiStyleConfig('BoxRadio', { isChecked, variant });
  const themeRadioProps = styles.radio as Partial<ComponentProps<typeof Radio>>;
  const disabled = groupDisabled ?? isDisabled;

  return (
    <Box
      __css={styles.container}
      onClick={() => {
        if (disabled) {
          return;
        }
        onChange?.(value);
      }}
    >
      <Box __css={styles.innerContainer}>
        <Box>
          <Label variant={variant === 'noBox' ? 'medium' : 'bold'}>{label}</Label>
          <Meta variant="regular">{description}</Meta>
        </Box>
        <Radio {...themeRadioProps} {...radioProps} isDisabled={disabled}>
          <VisuallyHidden>{label}</VisuallyHidden>
        </Radio>
      </Box>
      {children}
    </Box>
  );
};
