import { ReactNode } from 'react';
import { InputProps, Radio, Skeleton } from '@chakra-ui/react';
import { useTranslation } from 'react-i18next';
import { RadioButton } from './components/RadioButton';
import { useRadioGroupContext } from './components/RadioGroup/hooks/useRadioGroupContext';

export type RadioControlProps = InputProps & {
  children: ReactNode;
  isDefault?: boolean;
  isDisabled?: boolean;
  isLoaded?: boolean;
  value?: string;
};

export const RadioControl = ({
  children,
  isDefault,
  isDisabled,
  isLoaded = true,
  value,
  variant = 'radio',
  ...props
}: RadioControlProps) => {
  const { t: tCommon } = useTranslation('common');
  const { getRadioProps, variant: radioType } = useRadioGroupContext();
  const radioProps = getRadioProps({ value });

  if (radioType === 'button') {
    return (
      <Skeleton isLoaded={isLoaded}>
        <RadioButton {...radioProps}>{children}</RadioButton>;
      </Skeleton>
    );
  } else {
    return (
      <Skeleton isLoaded={isLoaded}>
        <Radio {...radioProps} isDisabled={isDisabled} variant={variant} {...props}>
          {children}
          {isDefault && ` (${tCommon('default').toLocaleLowerCase()})`}
        </Radio>
      </Skeleton>
    );
  }
};
