+import path from 'path';
+import { createRequire } from 'module';
+import { fileURLToPath } from 'url';
+import type { Page } from '@playwright/test';
+
+const require = createRequire(import.meta.url);
+const mswIifePath = require.resolve('msw/lib/iife/index.js');
+const __filename = fileURLToPath(import.meta.url);
+const __dirname = path.dirname(__filename);
+const setupScriptPath = path.resolve(__dirname, '../mocks/setupMsw.js');
+
+type Primitive = string | number | boolean | null;
+type Json = Primitive | Json[] | { [key: string]: Json };
+
+export type MswConfig = {
+  account?: Json;
+  accountDocuments?: Json[];
+  accountId: string;
+  bankAccounts?: Json[];
+  featureToggles?: Json[];
+  onboardingSurvey?: Json;
+  serviceWorkerUrl?: string;
+  user?: Json;
+};
+
+declare global {
+  interface Window {
+    __MSW_CONFIG__?: MswConfig;
+    __msw?: {
+      worker?: {
+        resetHandlers: () => void;
+        start: () => Promise<void>;
+        stop?: () => void;
+        use: (...handlers: unknown[]) => void;
+      };
+    };
+    MockServiceWorker?: {
+      rest: Record<string, unknown>;
+    };
+  }
+}
+
+export class Msw {
+  private started = false;
+
+  constructor(private readonly page: Page) {}
+
+  async start(config: MswConfig) {
+    if (this.started) {
+      throw new Error('MSW worker has already been started for this page.');
+    }
+
+    await this.page.addInitScript({ path: mswIifePath });
+    await this.page.addInitScript((cfg) => {
+      window.__MSW_CONFIG__ = cfg;
+    }, config);
+    await this.page.addInitScript({ path: setupScriptPath });
+
+    this.started = true;
+  }
+
+  async useJson(method: 'get' | 'post' | 'put' | 'patch' | 'delete', url: string, body: Json, status = 200) {
+    await this.page.evaluate(
+      ({ method, url, body, statusCode }) => {
+        const rest = window.MockServiceWorker?.rest as Record<string, unknown> | undefined;
+        const worker = window.__msw?.worker;
+
+        if (!worker || !rest) {
+          throw new Error('MSW worker is not initialized.');
+        }
+
+        const handlerFactory = rest[method];
+        if (typeof handlerFactory !== 'function') {
+          throw new Error(`MSW does not support method "${method}".`);
+        }
+
+        worker.use(
+          // @ts-ignore - runtime factory invocation
+          handlerFactory(url, (_req, res, ctx) => res(ctx.status(statusCode), ctx.json(body)))
+        );
+      },
+      { body, method, statusCode: status, url }
+    );
+  }
+
+  async resetHandlers() {
+    await this.page.evaluate(() => {
+      window.__msw?.worker?.resetHandlers();
+    });
+  }
+
+  async stop() {
+    await this.page.evaluate(() => {
+      window.__msw?.worker?.stop?.();
+    });
+  }
+}
