import { createContext, forwardRef, ReactNode } from 'react';
import { useRadioGroup, UseRadioGroupReturn } from '@chakra-ui/radio';
import { useMultiStyleConfig } from '@chakra-ui/react';
import { PropGetter } from '@chakra-ui/react-utils';
import { FormControl } from '@ui/components/formControls/FormControl';
import { BaseProps } from '@ui/components/formControls/baseProps';

type RadioPropGetter = PropGetter<
  HTMLInputElement,
  {
    /**
     * checked is defined if isNative=true
     */
    checked?: boolean;
    /**
     * isChecked is defined if isNative=false
     */
    isChecked?: boolean;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    onChange?: (e: any) => void;
    value?: string | number;
  } & Omit<React.InputHTMLAttributes<HTMLInputElement>, 'onChange' | 'size' | 'value'>
>;

export interface IRadioGroupContext {
  getRadioProps: RadioPropGetter;
  isDisabled?: boolean;
  variant: 'radio' | 'button' | 'icon';
}

export const RadioGroupContext = createContext<IRadioGroupContext>(null!);

export type IRadioGroupProps = BaseProps & {
  children: ReactNode;
  formHelperText?: ReactNode;
  isDisabled?: boolean;
  isInvalid?: boolean;
  onChange: (value: string | boolean) => void;
  value: string | boolean | undefined;
  variant?: 'radio' | 'button' | 'icon';
};

// eslint-disable-next-line @typescript-eslint/no-unused-vars
export const RadioGroup = forwardRef<HTMLInputElement, IRadioGroupProps>((props, _ref) => {
  const {
    children,
    formControlProps,
    formHelperText,
    isDisabled,
    isInvalid,
    isRequired,
    label,
    name,
    onChange,
    value,
    variant = 'radio',
  } = props;

  const formGroupStyles = useMultiStyleConfig('FormGroup', { variant: formControlProps?.variant });

  // HTML Radio Controls only support string values
  // with this we can use value="true | false" on radio controls
  // and still receive boolean in our form context
  const handleOnChange = (val: string | boolean) => {
    if (val === 'true') {
      onChange(true);
    } else if (val === 'false') {
      onChange(false);
    } else {
      onChange(val);
    }
  };

  const { getRadioProps }: UseRadioGroupReturn = useRadioGroup({
    name,
    onChange: handleOnChange,
    value: typeof value === 'boolean' ? `${value}` : value, // Form context will potentially provide boolean true | false
  });

  return (
    <FormControl
      className="radio-group-control"
      formHelperText={formHelperText}
      formLabelProps={{
        ...(formControlProps?.formLabelProps ?? {}),
        sx: formGroupStyles.label,
      }}
      isDisabled={isDisabled}
      isInvalid={isInvalid}
      isRequired={isRequired}
      label={label}
      name={name}
      sx={{ ...formGroupStyles.container }}
      {...formControlProps}
    >
      <RadioGroupContext.Provider value={{ getRadioProps, isDisabled, variant }}>
        {children}
      </RadioGroupContext.Provider>
    </FormControl>
  );
});
